code = """import json
import re

# Load citations
citations_file = locals()['var_function-call-3451325983418300049']
with open(citations_file, 'r') as f:
    citations = json.load(f)

citation_map = {}
for c in citations:
    fname = c['title'] + ".txt"
    citation_map[fname] = int(c['citation_count'])

# Load Chunks
chunk1_file = locals()['var_function-call-7997207072061889329']
with open(chunk1_file, 'r') as f:
    docs1 = json.load(f)

chunk2_file = locals()['var_function-call-8672902718240974531']
with open(chunk2_file, 'r') as f:
    docs2 = json.load(f)

all_docs = docs1 + docs2

total_citations = 0
chi_papers = []
debug_logs = []

target_paper = "Reflective Informatics: Conceptual Dimensions for Designing Technologies of Reflection.txt"

for doc in all_docs:
    filename = doc['filename']
    text = doc.get('text', '')
    
    # Check if this is the target paper to debug
    if filename == target_paper:
        debug_logs.append("Found target paper in docs.")
        # Check CHI
        header_text = text[:10000]
        match = re.search(r'\\bCHI\\b', header_text)
        if match:
            debug_logs.append("Target paper matched CHI regex.")
        else:
            debug_logs.append("Target paper DID NOT match CHI regex.")
    
    # Logic for all papers
    header_text = text[:10000]
    is_chi = False
    if re.search(r'\\bCHI\\b', header_text):
        is_chi = True
    elif "Conference on Human Factors in Computing Systems" in header_text:
        is_chi = True
    elif "CHI Conference" in header_text:
        is_chi = True
        
    if is_chi:
        if filename in citation_map:
            count = citation_map[filename]
            total_citations += count
            chi_papers.append(filename + " (" + str(count) + ")")

result = {
    "total_citations": total_citations,
    "chi_papers": chi_papers,
    "debug_logs": debug_logs,
    "total_docs": len(all_docs)
}

print("__RESULT__:")
print(json.dumps(result))"""

